// Generar las URLs de listado (paginación server-side ?pagina=N, 12 coches/pág, ~52 págs para 609).
const MAX = 55;
const out = [];
for (let p = 1; p <= MAX; p++) out.push({ json: { url: 'https://www.comprayconduce.es/coches-ocasion/?pagina=' + p } });
return out;

// Extraer todas las URLs de ficha de las ~55 páginas de listado ($input.all())
const inputs = $input.all();
const seen = {}; const urls = [];
for (const inp of inputs) {
  const html = typeof inp.json === 'string' ? inp.json : String(inp.json.data || inp.json.body || '');
  const re = /ficha-vehiculo-ocasion\/[a-z0-9-]+\/(\d+)/g;
  let m;
  while ((m = re.exec(html)) !== null) {
    const id = 'vian_' + m[1];
    if (seen[id]) continue; seen[id] = 1;
    urls.push({ id: id, url: 'https://www.comprayconduce.es/' + m[0] });
  }
}
return [{ json: { urls: urls, total: urls.length } }];

// Elegir N fichas/ejecución: primero las que faltan en BD, luego las más antiguas
const N = 400;
const urls = $('Code: Extraer fichas del listado').first().json.urls || [];
const byId = {}; urls.forEach(function (u) { byId[u.id] = u.url; });
const existing = $input.all().map(function (i) { return i.json; }).filter(function (e) { return e && e.id; });
const has = {}; existing.forEach(function (e) { has[e.id] = true; });
const missing = urls.filter(function (u) { return !has[u.id]; });
existing.sort(function (a, b) { return (Number(a.upd) || 0) - (Number(b.upd) || 0); });
const stale = existing.filter(function (e) { return byId[e.id]; }).map(function (e) { return { url: byId[e.id] }; });
const pick = missing.map(function (u) { return { url: u.url }; }).concat(stale).slice(0, N);
return pick.map(function (p) { return { json: { url: p.url } }; });

// Modrive – transform: ficha HTML → JSON-LD Vehicle → UPSERT en moveadvisor_marketplace_vo_offers
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');

function esc(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function normFuel(s) {
  s = String(s || '').toLowerCase();
  if (s.indexOf('electric') !== -1 && (s.indexOf('/') !== -1 || s.indexOf('hybrid') !== -1)) return 'Híbrido';
  if (s.indexOf('electric') !== -1 || s.indexOf('eléctric') !== -1) return 'Eléctrico';
  if (s.indexOf('hybrid') !== -1 || s.indexOf('híbrido') !== -1) return 'Híbrido';
  if (s.indexOf('diesel') !== -1 || s.indexOf('diésel') !== -1) return 'Diesel';
  if (s.indexOf('gasolin') !== -1 || s.indexOf('petrol') !== -1 || s.indexOf('gasoline') !== -1) return 'Gasolina';
  if (s.indexOf('glp') !== -1 || s.indexOf('lpg') !== -1 || s.indexOf('gas') !== -1) return 'Gas';
  return '';
}
function num(s) { const n = parseInt(String(s).replace(/[^\d]/g, ''), 10); return isNaN(n) ? null : n; }

// extraer el Vehicle del JSON-LD
let v = null;
const blocks = [...html.matchAll(/<script[^>]*type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/g)];
for (const b of blocks) {
  let o; try { o = JSON.parse(b[1]); } catch (e) { continue; }
  const arr = o['@graph'] || (Array.isArray(o) ? o : [o]);
  const find = (x) => { if (!x || typeof x !== 'object') return null; if (x['@type'] === 'Vehicle' || x['@type'] === 'Car') return x; for (const k in x) { const r = find(x[k]); if (r) return r; } return null; };
  v = find(arr);
  if (v) break;
}
if (!v) return [{ json: { sql: null, count: 0 } }];

const url = (v.offers && v.offers.url) || v.url || v['@id'] || '';
const idm = String(url).match(/\/(\d+)\/?$/);
const id = idm ? ('vian_' + idm[1]) : null;
const price = v.offers && v.offers.price ? num(v.offers.price) : null;
if (!id || price === null) return [{ json: { sql: null, count: 0 } }];

const brand = (v.brand && (v.brand.name || v.brand)) || '';
const model = v.model || '';
const title = (v.name || (brand + ' ' + model)).replace(/\s+/g, ' ').trim();
const version = v.vehicleConfiguration ? String(v.vehicleConfiguration).split(',')[0].trim() : '';
const _yr = (v.productionDate && String(v.productionDate).match(/(\d{4})/)) || (v.vehicleModelDate && String(v.vehicleModelDate).match(/(\d{4})/)) || (v.dateVehicleFirstRegistered && String(v.dateVehicleFirstRegistered).match(/(\d{4})/));
const year = _yr ? _yr[1] : null;
const mileage = v.mileageFromOdometer ? num(v.mileageFromOdometer.value != null ? v.mileageFromOdometer.value : v.mileageFromOdometer) : null;
const fuel = normFuel(v.fuelType || (v.vehicleEngine && v.vehicleEngine.engineType));
const transmission = /manual/i.test(v.vehicleTransmission || '') ? 'Manual' : (/autom/i.test(v.vehicleTransmission || '') ? 'Automatica' : '');
let powerVal = null;
if (v.vehicleEngine && v.vehicleEngine.enginePower && v.vehicleEngine.enginePower.value != null) {
  const rawp = num(v.vehicleEngine.enginePower.value);
  const unit = String(v.vehicleEngine.enginePower.unitCode || v.vehicleEngine.enginePower.unitText || '').toUpperCase();
  if (rawp) powerVal = (unit.indexOf('KW') !== -1) ? Math.round(rawp * 1.35962) : rawp; // kW→CV
}
const power = powerVal ? (powerVal + ' CV') : null;
const bodyType = v.bodyType || '';
const doors = (v.numberOfDoors != null) ? parseInt(v.numberOfDoors, 10) : null;
const color = v.color || '';
const imgs = Array.isArray(v.image) ? v.image.filter(Boolean).slice(0, 15) : (v.image ? [v.image] : []);
const imageUrl = imgs[0] || '';
const imagesJson = JSON.stringify(imgs).replace(/'/g, "''");
const condition = (mileage !== null && mileage < 1000) ? 'nuevo' : 'usado';

const cols = 'id, title, brand, model, version, price, year, mileage, fuel, power, transmission, ' +
  'color, image_url, image_urls, source_url, vehicle_condition, seller_type, portal, seller, ' +
  'available_for_purchase, is_active, created_at, updated_at';

const vals = '(' +
  esc(id) + ', ' + esc(title) + ', ' + esc(brand) + ', ' + esc(model) + ', ' + esc(version) + ', ' +
  price + ', ' + (year || 'NULL') + ', ' + (mileage !== null ? mileage : 'NULL') + ', ' +
  esc(fuel) + ', ' + esc(power) + ', ' + esc(transmission) + ', ' +
  esc(color) + ', ' + esc(imageUrl) + ", '" + imagesJson + "', " + esc(url) + ', ' +
  esc(condition) + ", 'concesionario', 'vian', 'VIAN', true, true, NOW(), NOW()" +
')';

const onConflict = 'ON CONFLICT (id) DO UPDATE SET ' +
  'title = EXCLUDED.title, price = EXCLUDED.price, mileage = EXCLUDED.mileage, ' +
  'version = EXCLUDED.version, fuel = EXCLUDED.fuel, power = EXCLUDED.power, transmission = EXCLUDED.transmission, ' +
  "image_url = COALESCE(NULLIF(moveadvisor_marketplace_vo_offers.image_url,''), EXCLUDED.image_url), " +
  'image_urls = EXCLUDED.image_urls, vehicle_condition = EXCLUDED.vehicle_condition, ' +
  'is_active = TRUE, updated_at = NOW()';

const sql = 'INSERT INTO moveadvisor_marketplace_vo_offers (' + cols + ') VALUES ' + vals + ' ' + onConflict;
return [{ json: { sql: sql, count: 1, id: id } }];
